############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $r = list_random(2,3,5,6,7,10); @ORCCA_variables = grep {!/[eoEOU]/} ('a' .. 'z', 'A' .. 'Z'); $var = list_random(@ORCCA_variables); Context("Form")->variables->are($var=>'Real'); $n = random(3 .. 9); $f = Compute("$var^(2*$n) - $r**2")->reduce; $answer = Compute("($var^$n + $r)($var^$n - $r)");
############################################################ # Body ############################################################
BEGIN_PGML Factor the polynomial. It is important to try to recognize a special pattern can be used. If you factor these using another method, you are missing the opportunity to practice learning the special patterns.
[`[$f]`]
[_]{$answer}{16}
END_PGML
